class Solution:
    def isValidSudoku(self, board: List[List[str]]) -> bool:

        # horizontal check
        for x in board:
            check: set = set()
            for item in x:
                if item == '.':
                    continue
                if item in check:
                    return False
                check.add(item)

        # verticle check
        for y in range(9):
            check: set = set()
            for x in range(9):
                if board[x][y] == '.':
                    continue
                if board[x][y] in check:
                    return False
                check.add(board[x][y])

        # grid check
        for i in range(3):
            for j in range(3):
                check: set = set()
                x_index, y_index = i * 3, j * 3
                for x_in in range(3):
                    for y_in in range(3):
                        x, y = x_in + x_index, y_in + y_index
                        if board[x][y] == '.':
                            continue
                        if board[x][y] in check:
                            return False
                        check.add(board[x][y])

        return True
